module RefModule(
    input clk,
    input reset,
    input enable,
    input clear,
    output reg [1:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, posedge reset or posedge dbg_halt) begin
		if (reset)
			q <= 0;
		else if (clear)
			q <= 0;
		else if (enable)
			q <= q + 1;
	end
endmodule
